import React from 'react';
import ProjectCard from './ProjectCard';
import { Project } from '../types';
import { getVimeoEmbedUrl } from '../utils/video'; // <- new import

const placeholder = (n: number) => `https://via.placeholder.com/1200x675?text=Project+${n}`;

const placeholderProjects: Project[] = [
  { id: 'p1', title: "Trujistas 'It's A Lifestyle'", description: '', thumbnail: placeholder(1), link: 'https://vimeo.com/1185046543?h=HASH', category: 'Selected Work', role: 'DIRECTOR', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p2', title: "Epiclesis 'Short Film'", description: '', thumbnail: placeholder(2), link: '#', category: 'Narrative', role: 'DIRECTOR', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p3', title: "Moeder 'Short Film'", description: '', thumbnail: placeholder(3), link: '#', category: 'Narrative', role: 'EDITOR', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p4', title: "HP 'The Wrong Kind of Busy'", description: '', thumbnail: placeholder(4), link: '#', category: 'Commercials', role: 'DIRECTOR', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p5', title: "Young Fathers 'Mr. Martyr'", description: '', thumbnail: placeholder(5), link: '#', category: 'Music Videos', role: 'EDITOR', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p6', title: "NBA 'Don't Miss a Thing'", description: '', thumbnail: placeholder(6), link: '#', category: 'Commercials', role: 'DIRECTOR', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p7', title: "Beyond the Endless Light", description: '', thumbnail: placeholder(7), link: '#', category: 'Selected Work', role: 'EDITOR', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p8', title: "House of Diligence 'Documentary'", description: '', thumbnail: placeholder(8), link: '#', category: 'Format Agnostic', role: 'DIRECTOR', createdAt: new Date(), updatedAt: new Date() },
];

interface ProjectListProps {
  selectedCategory?: string;
  selectedRole?: string | null;
}

const ProjectList: React.FC<ProjectListProps> = ({ selectedCategory = 'All Projects', selectedRole = null }) => {
  const normalizedProjects: Project[] = placeholderProjects.map(p => ({
    ...p,
    // ensure we preserve hash in embed-ready URL
    // @ts-ignore allow adding videoUrl if not declared in Project type
    videoUrl: getVimeoEmbedUrl(p.link),
  }));

  const byCategory = selectedCategory === 'All Projects'
    ? normalizedProjects
    : normalizedProjects.filter(p => p.category === selectedCategory);

  return (
    <section className="project-grid">
      {byCategory.map((project, index) => {
        const nonMatchRole = selectedRole && project.role !== selectedRole;
        return (
          <div
            className={`project-card ${nonMatchRole ? 'fade-nonmatch' : ''}`}
            key={project.id}
          >
            <ProjectCard project={project as Project} index={index} />
          </div>
        );
      })}
    </section>
  );
};

export default ProjectList;
